1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a live cell with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with exactly two neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    const sorted = result.map(([x, y]) => [x, y]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    expect(sorted).toEqual([[1, -1], [1, 0], [1, 1]]);
18	  });
19	  it("should keep a live cell alive with exactly three neighbors (survival)", () => {
20	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
21	    const sorted = result.map(([x, y]) => [x, y]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);
22	    expect(sorted).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
23	  });
24	  it("should kill a live cell with four neighbors (overpopulation)", () => {
25	    const cross: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
26	    const result = nextGeneration(cross);
27	    const sorted = result.map(([x, y]) => [x, y]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);
28	    const centerAlive = sorted.some(([x, y]) => x === 1 && y === 1);
29	    expect(centerAlive).toBe(false);
30	  });
31	  it("should create a live cell from a dead cell with exactly three live neighbors (reproduction)", () => {
32	    // Gen 0: cells (0,0), (0,1), (1,1) — dead cell (1,0) has 3 live neighbors
33	    const result = nextGeneration([[0, 0], [0, 1], [1, 1]]);
34	    const sorted = result.map(([x, y]) => [x, y]).sort((a, b) => a[0] - b[0] || a[1] - b[1]);
35	    expect(sorted).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
36	  });
37	  it.todo("should not create a live cell from a dead cell with only two live neighbors");
38	  it.todo("should handle a block still life (2x2 square remains unchanged)");
39	  it.todo("should handle a blinker oscillator (three in a row toggles orientation)");
40	  it.todo("should support negative coordinates");
41	});
