1	function cellKey(x: number, y: number): string {
2	  return `${x},${y}`;
3	}
4	
5	function parseKey(key: string): [number, number] {
6	  const [x, y] = key.split(",").map(Number);
7	  return [x, y];
8	}
9	
10	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
11	  if (liveCells.length === 0) return [];
12	
13	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
14	  const neighborCounts = new Map<string, number>();
15	
16	  for (const [x, y] of liveCells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        if (dx === 0 && dy === 0) continue;
20	        const key = cellKey(x + dx, y + dy);
21	        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
22	      }
23	    }
24	  }
25	
26	  const result: [number, number][] = [];
27	  for (const [key, count] of neighborCounts) {
28	    const isAlive = liveSet.has(key);
29	    const survives = isAlive && (count === 2 || count === 3);
30	    const born = !isAlive && count === 3;
31	    if (survives || born) {
32	      result.push(parseKey(key));
33	    }
34	  }
35	
36	  return result;
37	}
